// Load project configuration from file
const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/.n8n/config.json', 'utf8'));
return [{ json: config }];

// Check if today is Yom Kodesh (Shabbat or Chag)
// Also check if there's a transition to Chol at sunset today
const config = $('Load Config').first().json;
const LAT = config.settings.LATITUDE;
const LON = config.settings.LONGITUDE;

const today = new Date();
const dateStr = today.toISOString().slice(0, 10);
const tomorrow = new Date(today.getTime() + 24 * 60 * 60 * 1000);
const tomorrowStr = tomorrow.toISOString().slice(0, 10);

// Get Hebcal data
const url = `https://www.hebcal.com/shabbat?cfg=json&latitude=${LAT}&longitude=${LON}&M=on&b=18`;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  json: true
});

// Determine if today is Kodesh
// Today is Kodesh if:
// - It's Saturday (day 6)
// - Or there was candle lighting yesterday (holiday)
// - Or Hebcal shows havdalah for today

let isYomKodesh = (today.getDay() === 6); // Saturday
let havdalahToday = null;
let candleLightingToday = null;
let transitionToChol = false;

for (const item of response.items || []) {
  const itemDate = item.date ? item.date.slice(0, 10) : '';

  // If havdalah is today, there's a transition to Chol
  if (item.category === 'havdalah' && itemDate === dateStr) {
    havdalahToday = item.date;
    transitionToChol = true;
  }

  // If candle lighting was yesterday or today is between candles and havdalah
  if (item.category === 'candles' && itemDate === dateStr) {
    candleLightingToday = item.date;
    // If there's candle lighting today, it means today is also erev (handled by other workflow)
  }
}

// Also check: if today is Saturday, it's definitely Kodesh
// If today is a holiday (check Hebrew calendar)
const hebcalCalUrl = `https://www.hebcal.com/hebcal?v=1&cfg=json&year=now&month=now&maj=on&min=off&mod=off&nx=off&ss=off&mf=off&c=off&geo=pos&latitude=${LAT}&longitude=${LON}`;

const calResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: hebcalCalUrl,
  json: true
});

// Check if today is a Yom Tov
for (const item of calResponse.items || []) {
  const itemDate = item.date ? item.date.slice(0, 10) : '';
  if (itemDate === dateStr && item.yomtov === true) {
    isYomKodesh = true;
  }
}

const month = today.getMonth() + 1;
const isSummerMonth = config.settings.SUMMER_MONTHS.includes(month);

// Get sunset time for today (from Hebcal zmanim)
const zmanimUrl = `https://www.hebcal.com/zmanim?cfg=json&latitude=${LAT}&longitude=${LON}&date=${dateStr}`;
const zmanimResp = await this.helpers.httpRequest({
  method: 'GET',
  url: zmanimUrl,
  json: true
});
const sunset = zmanimResp.times?.sunset || null;

return [{
  json: {
    isYomKodesh,
    transitionToChol,
    havdalahToday,
    sunset,
    isSummerMonth,
    month,
    dateStr
  }
}];

// Get weather forecast for the next 36 hours from Tomorrow.io
const config = $('Load Config').first().json;
const LAT = config.settings.LATITUDE;
const LON = config.settings.LONGITUDE;
const API_KEY = config.secrets.TOMORROW_IO_KEY;

const url = `https://api.tomorrow.io/v4/weather/forecast?location=${LAT},${LON}&timesteps=1h&apikey=${API_KEY}`;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  json: true
});

// Extract relevant hourly data for the next 36 hours
const hourly = (response.timelines?.hourly || []).slice(0, 36).map(h => ({
  time: h.time,
  temperature: h.values?.temperature,
  humidity: h.values?.humidity,
  cloudCover: h.values?.cloudCover,
  weatherCode: h.values?.weatherCode
}));

// Calculate max temperature for today/tomorrow
const maxTemp = Math.max(...hourly.map(h => h.temperature || 0));

return [{
  json: {
    forecast: hourly,
    maxTemp,
    currentTemp: hourly[0]?.temperature || null
  }
}];

// AI Yom Kodesh Steward - Manages Shabbat/Chag day schedule
// Runs at 11:00 on Shabbat/Chag to manage daytime actions
const config = $('Load Config').first().json;
const kodeshData = $('Check Yom Kodesh').first().json;
const weatherData = $('Get Weather Forecast').first().json;

const GEMINI_KEY = config.secrets.GEMINI_API_KEY;
const devices = config.devices;

const prompt = `You are the "AI Shabbat Day Steward," managing a smart home DURING Shabbat/Chag.
It is currently Yom Kodesh (Shabbat or Holiday). You must plan the remaining actions for today.

IMPORTANT: All actions were pre-scheduled before Shabbat. You are now executing the DAYTIME portion.
No new halachic issues - these are pre-programmed timers running automatically.

Available smart entities:
- Living Room ACs (2 units: ID="${devices.AC_LIVING_1}" and ID="${devices.AC_LIVING_2}")
- Bedroom AC (ID="${devices.AC_BEDROOM}")
- Kids Room AC (ID="${devices.AC_KIDS}")
- Kitchen AC (ID="${devices.AC_KITCHEN}")
- Mini-Bar Plug (ID="${devices.MINI_BAR}" - code "switch_1")
- Living Room Shutters (Left="${devices.SHUTTER_LEFT}", Right="${devices.SHUTTER_RIGHT}")

Context:
- Today: ${kodeshData.dateStr}
- Is Yom Kodesh: ${kodeshData.isYomKodesh}
- Transition to Chol today: ${kodeshData.transitionToChol}
- Havdalah time: ${kodeshData.havdalahToday || 'No havdalah today (multi-day chag)'}
- Sunset: ${kodeshData.sunset}
- Is Summer: ${kodeshData.isSummerMonth}
- Month: ${kodeshData.month}
- Weather forecast: ${JSON.stringify(weatherData.forecast.slice(0, 12))}
- Max Temperature: ${weatherData.maxTemp}°C
- Current Temperature: ${weatherData.currentTemp}°C

RULES:
1. Turn OFF bedroom/kids ACs at 11:00 (they ran all night).
2. Kitchen AC ON at 11:30, OFF at 12:00 (pre-lunch cooling).
3. Living room ACs ON 12:00-14:00 for Shabbat lunch (summer + hot only).
4. Bedroom AC ON 14:00 until sunset (always in summer for afternoon rest).
5. Kids AC ON 14:00 until sunset (only if temp > 20°C).
6. If transition to Chol (havdalah today): Turn ON Mini-Bar at havdalah time.
7. Shutters: Adjust based on sun position and heat.
8. Skip AC actions if NOT summer month (5-10) or temperature < 20°C (except bedroom which is always on in summer).

Output ONLY valid JSON:
{
  "reasoning_summary": "Brief Hebrew summary of today's plan",
  "schedule": [
    {
      "time": "YYYY-MM-DDTHH:MM:SS+03:00",
      "deviceId": "tuya_device_id",
      "entity": "entity_name",
      "action": "ON/OFF/SET",
      "commands": [{"code": "command_code", "value": "value"}],
      "explanation": "Why (in Hebrew)"
    }
  ]
}`;

const payload = {
  contents: [{ role: "user", parts: [{ text: prompt }] }],
  generationConfig: {
    responseMimeType: "application/json",
    responseSchema: {
      type: "object",
      properties: {
        reasoning_summary: { type: "string" },
        schedule: {
          type: "array",
          items: {
            type: "object",
            properties: {
              time: { type: "string" },
              deviceId: { type: "string" },
              entity: { type: "string" },
              action: { type: "string" },
              commands: {
                type: "array",
                items: {
                  type: "object",
                  properties: {
                    code: { type: "string" },
                    value: {}
                  }
                }
              },
              explanation: { type: "string" }
            },
            required: ["time", "deviceId", "entity", "action", "commands", "explanation"]
          }
        }
      },
      required: ["reasoning_summary", "schedule"]
    }
  }
};

const url = "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=" + GEMINI_KEY;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    body: payload,
    json: true,
    headers: { 'Content-Type': 'application/json' }
  });

  const text = response.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json|```/g, '').trim();
  const result = JSON.parse(cleaned);

  return [{ json: result }];
} catch (e) {
  return [{ json: {
    reasoning_summary: "שגיאה בקבלת תשובה מ-AI",
    schedule: [],
    error: e.message
  }}];
}

// Execute scheduled Tuya commands at the right times
// This node receives a schedule array and executes commands that are due NOW
const crypto = require('crypto');
const config = $('Load Config').first().json;
const scheduleData = $input.first().json;

const TUYA_ACCESS_ID = config.secrets.TUYA_ACCESS_ID;
const TUYA_ACCESS_SECRET = config.secrets.TUYA_ACCESS_SECRET;
const API_URL = 'https://openapi.tuyaeu.com';

// Get Tuya token
async function getTuyaToken() {
  const timestamp = Date.now().toString();
  const path = '/v1.0/token?grant_type=1';
  const contentHash = crypto.createHash('sha256').update('').digest('hex');
  const stringToSign = 'GET\n' + contentHash + '\n\n' + path;
  const str = TUYA_ACCESS_ID + timestamp + stringToSign;
  const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: API_URL + path,
    headers: { 't': timestamp, 'sign': sign, 'client_id': TUYA_ACCESS_ID, 'sign_method': 'HMAC-SHA256' },
    json: true
  });

  return response.result.access_token;
}

// Send command to device
async function sendCommand(token, deviceId, commands) {
  const timestamp = Date.now().toString();
  const path = '/v1.0/devices/' + deviceId + '/commands';
  const body = JSON.stringify({ commands });

  const contentHash = crypto.createHash('sha256').update(body).digest('hex');
  const stringToSign = 'POST\n' + contentHash + '\n\n' + path;
  const str = TUYA_ACCESS_ID + token + timestamp + stringToSign;
  const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: API_URL + path,
    headers: {
      't': timestamp, 'sign': sign, 'client_id': TUYA_ACCESS_ID,
      'sign_method': 'HMAC-SHA256', 'access_token': token,
      'Content-Type': 'application/json'
    },
    body: body,
    json: true
  });

  return response;
}

// Filter actions that should execute NOW (within 2 minute window)
const now = Date.now();
const WINDOW_MS = 2 * 60 * 1000; // 2 minutes

const dueActions = scheduleData.schedule.filter(action => {
  const actionTime = new Date(action.time).getTime();
  return Math.abs(actionTime - now) <= WINDOW_MS;
});

if (dueActions.length === 0) {
  return [{ json: { executed: 0, message: 'No actions due at this time' } }];
}

// Execute due actions
const token = await getTuyaToken.call(this);
const results = [];

for (const action of dueActions) {
  try {
    const result = await sendCommand.call(this, token, action.deviceId, action.commands);
    results.push({
      entity: action.entity,
      action: action.action,
      success: result.success,
      time: action.time
    });
  } catch (e) {
    results.push({
      entity: action.entity,
      action: action.action,
      success: false,
      error: e.message,
      time: action.time
    });
  }
}

return [{ json: { executed: results.length, results } }];
